WHERE board_type = #{boardType}

  AND (title LIKE '%' || #{searchKeyword} || '%' OR content LIKE '%' || #{searchKeyword} || '%' OR author_name LIKE '%' || #{searchKeyword} || '%')

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM board_articles
WHERE board_type = #{boardType}

  AND (title LIKE '%' || #{searchKeyword} || '%' OR content LIKE '%' || #{searchKeyword} || '%' OR author_name LIKE '%' || #{searchKeyword} || '%')

